Here's a complete example:

**XAML**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <RefreshView Command="{Binding RefreshCommand}"
                 IsRefreshing="{Binding IsRefreshing}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem}"
                        SelectionChangedCommand="{Binding SelectionChangedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate>
                    <Grid Padding="12" ColumnDefinitions="*,Auto">
                        <Label Text="{Binding Name}" FontSize="16" />
                        <Label Grid.Column="1" Text="{Binding Status}"
                               TextColor="Gray" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
        </CollectionView>

    </RefreshView>
</ContentPage>
```

**ViewModel** (using CommunityToolkit.Mvvm)
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private ItemModel? _selectedItem;

    public ObservableCollection<ItemModel> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        var data = await _api.GetItemsAsync();
        Items.Clear();
        foreach (var item in data)
            Items.Add(item);
        IsRefreshing = false;          // stops the spinner
    }

    [RelayCommand]
    private async Task SelectionChangedAsync()
    {
        if (SelectedItem is null) return;
        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            ["Item"] = SelectedItem
        });
        SelectedItem = null;           // reset so the same row can be re-selected
    }
}
```

**Key binding relationships:**

| XAML property | ViewModel member | Purpose |
|---|---|---|
| `RefreshView.Command` | `RefreshCommand` | Triggers API reload on pull-down |
| `RefreshView.IsRefreshing` | `IsRefreshing` | Controls spinner; set `false` when done |
| `CollectionView.ItemsSource` | `Items` (ObservableCollection) | Drives the list; auto-updates UI on add/remove |
| `CollectionView.SelectedItem` | `SelectedItem` | Two-way bound; null it after navigation so the row can be tapped again |
| `SelectionChangedCommand` | `SelectionChangedCommand` | Fires on tap → navigates to detail page |

**Important details:**

- **`SelectionMode="Single"`** — only one item highlights at a time.
- **Reset `SelectedItem = null`** after navigating, otherwise tapping the same row a second time won't fire the command.
- **Set `IsRefreshing = false`** at the end of your refresh logic; the `RefreshView` won't stop the spinner on its own.
- Pass data to the detail page via Shell navigation parameters or a shared service, then receive it with `[QueryProperty]` on the detail VM.
